import{_ as e,c as a,o as r,a as t}from"./app.0f584d7b.js";const f=JSON.parse('{"title":"Introducci\xF3n","description":"","frontmatter":{},"headers":[],"relativePath":"start/intro.md"}'),o={name:"start/intro.md"},i=t('<h1 id="introduccion" tabindex="-1">Introducci\xF3n <a class="header-anchor" href="#introduccion" aria-hidden="true">#</a></h1><p>El aprendizaje del marco t\xE9cnico Scrum es el primer paso aconsejable para familiarizarse con la Gesti\xF3n \xC1gil. Inicialmente se recomienda adoptarlo aplicando reglas definidas adoptando <a href="./../pillars/intro.html">los pilares</a>, <a href="./../roles/role-definition.html">los roles</a>, <a href="./../artifacts/intro.html">los artefactos</a> y <a href="./../events/intro.html">los eventos</a> originales.</p><p>Una vez iniciados en Scrum, y con el conocimiento que el propio equipo acumula a trav\xE9s de las retrospectivas, se pueden ir <em>\u201Crompiendo\u201D</em> las reglas y adoptar la parte pragm\xE1tica, personalizada y m\xE1s adecuada a las propias circunstancias del propio equipo y proyecto.</p><blockquote><p>Seg\xFAn <a href="https://en.wikipedia.org/wiki/Jeff_Sutherland" target="_blank" rel="noreferrer">Jeff Sutherland</a>, uno de los creadores de Scrum y del m\xE9todo de control emp\xEDrico de procesos en el cual se basa dicha metodolog\xEDa, \xE9ste se sostiene en la implementaci\xF3n de tres pilares: <strong>transparencia</strong> (visibilidad de los procesos), <strong>inspecci\xF3n</strong> (peri\xF3dica del proceso) y <strong>adaptaci\xF3n</strong> (de los procesos inspeccionado).</p></blockquote><p>La <a href="./../pillars/transparency.html">transparencia</a>, la <a href="./../pillars/inspection.html">inspecci\xF3n</a> y la <a href="./../pillars/adaptation.html">adaptaci\xF3n</a> son conceptos estrechamente relacionados, cuya finalidad es permitir que un equipo pueda mejorar y entregar productos de valor en el momento indicado. Scrum brinda las herramientas y los momentos adecuados para que estos tres pilares puedan verse reflejados a lo largo de todo el proceso.</p><p>Esta parte del temario ense\xF1a la parte t\xE9cnica, basado en la aplicaci\xF3n de reglas concretas en un marco de <strong>roles</strong>, <strong>artefactos</strong> y <strong>eventos</strong> definidos.</p><p><strong>Marco T\xE9cnico</strong></p><ul><li><strong>Roles</strong><ul><li><a href="./../roles/product-owner.html">El Due\xF1o del Producto</a></li><li><a href="./../roles/project-manager.html">El Gestor del Proyecto</a></li><li><a href="./../roles/development-team.html">El Equipo de Desarrollo</a></li><li><a href="./../roles/development-leader.html">El L\xEDder de Desarrollo</a></li><li><a href="./../roles/test-team.html">El Equipo de Pruebas</a></li></ul></li><li><strong>Artefactos</strong><ul><li><a href="./../artifacts/user-stories.html">Historia de Usuario</a></li><li><a href="./../artifacts/technical-stories.html">Historias T\xE9cnicas</a></li><li><a href="./../artifacts/product-backlog.html">Pila del Producto</a></li><li><a href="./../artifacts/sprint-backlog.html">Pila del Sprint</a></li><li><a href="./../artifacts/increment.html">Incremento</a></li></ul></li><li><strong>Eventos</strong><ul><li><a href="./../events/sprint-planning.html">Reuni\xF3n de Planificaci\xF3n del Sprint</a></li><li><a href="./../events/daily-opening.html">Reuni\xF3n de Apertura Diaria</a></li><li><a href="./../events/sprint.html">Sprint</a></li><li><a href="./../events/sprint-review.html">Revisi\xF3n del Sprint</a></li><li><a href="./../events/sprint-retrospective.html">Retrospectiva del Sprint</a></li></ul></li></ul>',8),l=[i];function s(n,c,d,p,m,h){return r(),a("div",null,l)}const g=e(o,[["render",s]]);export{f as __pageData,g as default};
